/// The range list for a Java General_Category name ("L", "Lu", "Zs", …),
/// or null for an unknown name (the compiler raises NotImplemented).
pub fn rangesOf(name: []const u8) ?[]const CpRange {
    if (std.mem.eql(u8, name, "Cc")) return &CAT_CC;
    if (std.mem.eql(u8, name, "Cf")) return &CAT_CF;
    if (std.mem.eql(u8, name, "Co")) return &CAT_CO;
    if (std.mem.eql(u8, name, "Cs")) return &CAT_CS;
    if (std.mem.eql(u8, name, "Ll")) return &CAT_LL;
    if (std.mem.eql(u8, name, "Lm")) return &CAT_LM;
    if (std.mem.eql(u8, name, "Lo")) return &CAT_LO;
    if (std.mem.eql(u8, name, "Lt")) return &CAT_LT;
    if (std.mem.eql(u8, name, "Lu")) return &CAT_LU;
    if (std.mem.eql(u8, name, "Mc")) return &CAT_MC;
    if (std.mem.eql(u8, name, "Me")) return &CAT_ME;
    if (std.mem.eql(u8, name, "Mn")) return &CAT_MN;
    if (std.mem.eql(u8, name, "Nd")) return &CAT_ND;
    if (std.mem.eql(u8, name, "Nl")) return &CAT_NL;
    if (std.mem.eql(u8, name, "No")) return &CAT_NO;
    if (std.mem.eql(u8, name, "Pc")) return &CAT_PC;
    if (std.mem.eql(u8, name, "Pd")) return &CAT_PD;
    if (std.mem.eql(u8, name, "Pe")) return &CAT_PE;
    if (std.mem.eql(u8, name, "Pf")) return &CAT_PF;
    if (std.mem.eql(u8, name, "Pi")) return &CAT_PI;
    if (std.mem.eql(u8, name, "Po")) return &CAT_PO;
    if (std.mem.eql(u8, name, "Ps")) return &CAT_PS;
    if (std.mem.eql(u8, name, "Sc")) return &CAT_SC;
    if (std.mem.eql(u8, name, "Sk")) return &CAT_SK;
    if (std.mem.eql(u8, name, "Sm")) return &CAT_SM;
    if (std.mem.eql(u8, name, "So")) return &CAT_SO;
    if (std.mem.eql(u8, name, "Zl")) return &CAT_ZL;
    if (std.mem.eql(u8, name, "Zp")) return &CAT_ZP;
    if (std.mem.eql(u8, name, "Zs")) return &CAT_ZS;
    if (std.mem.eql(u8, name, "C")) return &MAJ_C;
    if (std.mem.eql(u8, name, "L")) return &MAJ_L;
    if (std.mem.eql(u8, name, "M")) return &MAJ_M;
    if (std.mem.eql(u8, name, "N")) return &MAJ_N;
    if (std.mem.eql(u8, name, "P")) return &MAJ_P;
    if (std.mem.eql(u8, name, "S")) return &MAJ_S;
    if (std.mem.eql(u8, name, "Z")) return &MAJ_Z;
    return null;
}

test "category sanity" {
    const lu = rangesOf("Lu").?;
    try std.testing.expect(lu.len > 100);
    const l = rangesOf("L").?;
    try std.testing.expect(l.len > 100);
    try std.testing.expect(rangesOf("Zz") == null);
}
